import pandas as pd
import requests

#当前爬虫时间：xxx

#爬虫返回的数据是json串，从中取出需要的属性
def show_final_result(json):
    if json:
        items = json.get('comments')
        for item in items:
            ls = {}
            ls['id'] = item.get('id')
            ls['score']=item.get('score')
            ls['content'] = item.get('content')
            ls['nickname']=item.get('nickname')
            ls['location'] = item.get('location')
            ls['creationTime'] = item.get('creationTime')
            yield ls


